params.bodyScript:
const svg = $('#c1-svg');
const kIn = $('#c1-k'), lIn = $('#c1-l'), kVal = $('#c1-k-val'), lVal = $('#c1-l-val');
const cobBtn = $('#c1-coboundary');
const ro = $('#c1-ro');
let cobMode = false;
let s0 = 0, s1 = 0;

function draw(){
  while(svg.firstChild) svg.removeChild(svg.firstChild);
  const k = +kIn.value, l = +lIn.value;
  kVal.textContent = `t_{01}^{right} = ${k}`;
  lVal.textContent = `t_{01}^{left} = ${l}`;

  const W=820, H=360, cx=W/2, cy=H/2-10, R=120;
  // draw two arcs (U_0 upper, U_1 lower), with overlap emphasized
  // U_0: angle from -20 deg to 200 deg
  const toRad = d => d*Math.PI/180;
  const arc = (a1, a2, color, w=14)=>{
    const large = (a2 - a1 > 180)?1:0;
    const x1 = cx + R*Math.cos(toRad(a1)), y1 = cy - R*Math.sin(toRad(a1));
    const x2 = cx + R*Math.cos(toRad(a2)), y2 = cy - R*Math.sin(toRad(a2));
    svg.appendChild(SVG('path',{d:`M${x1} ${y1} A ${R} ${R} 0 ${large} 0 ${x2} ${y2}`,
      fill:'none',stroke:color,'stroke-width':w,'stroke-linecap':'round','stroke-opacity':0.55}));
  };
  // U_0 upper arc, a bit past the horizontal
  arc(-20, 200, 'var(--blue)');
  // U_1 lower arc
  arc(160, 380, 'var(--pink)');
  // overlap regions highlighted
  arc(160, 200, 'var(--yellow)', 6);   // left overlap
  arc(-20, 20, 'var(--yellow)', 6);    // right overlap  (angles 340..20 wrap; use 20..-20 going clockwise → passes through 0)
  // Actually redo right: from -20 to 20 going through 0 is a short arc
  // quick fix: explicit small arc
  (function(){
    const a1=20, a2=-20;
    const x1 = cx + R*Math.cos(toRad(a1)), y1 = cy - R*Math.sin(toRad(a1));
    const x2 = cx + R*Math.cos(toRad(a2)), y2 = cy - R*Math.sin(toRad(a2));
    svg.appendChild(SVG('path',{d:`M${x1} ${y1} A ${R} ${R} 0 0 1 ${x2} ${y2}`,
      fill:'none',stroke:'var(--yellow)','stroke-width':6,'stroke-linecap':'round','stroke-opacity':0.9}));
  })();

  // labels
  const lab = (x,y,txt,color='#fff',fs=14, anchor='middle')=>{
    const t = SVG('text',{x,y,'font-size':fs,fill:color,'text-anchor':anchor,'font-weight':600});
    t.textContent = txt; svg.appendChild(t);
  };
  lab(cx, cy - R - 18, 'U₀', 'var(--blue)', 15);
  lab(cx, cy + R + 32, 'U₁', 'var(--pink)', 15);
  lab(cx + R + 24, cy + 4, 'right overlap', 'var(--yellow)', 12, 'start');
  lab(cx - R - 24, cy + 4, 'left overlap', 'var(--yellow)', 12, 'end');

  // show cocycle values on overlaps
  lab(cx + R + 24, cy + 22, `t = ${k}`, '#fff', 13, 'start');
  lab(cx - R - 24, cy + 22, `t = ${l}`, '#fff', 13, 'end');

  // if cobMode, attempt to write as coboundary
  // Right overlap: s1 - s0 = k ; Left overlap: s1 - s0 = l.
  // This system is consistent iff k == l. If consistent, s0=0, s1=k.
  let consistent = (k === l);
  let msgHtml;
  if(cobMode){
    if(consistent){
      s0 = 0; s1 = k;
      lab(cx - 95, cy - R + 30, `s₀ = ${s0}`, 'var(--green)', 14);
      lab(cx + 95, cy + R - 16, `s₁ = ${s1}`, 'var(--green)', 14);
      msgHtml = `<span style="color:var(--green)">Coboundary: t = d(s₀, s₁) with s₀ = ${s0}, s₁ = ${s1}. Class in H¹ is trivial.</span>`;
    } else {
      lab(cx - 95, cy - R + 30, '?', 'var(--pink)', 14);
      lab(cx + 95, cy + R - 16, '?', 'var(--pink)', 14);
      msgHtml = `<span style="color:var(--pink)">Not a coboundary: need s₁ - s₀ = ${k} (right) AND s₁ - s₀ = ${l} (left). Incompatible.</span><br>`+
                `Class in H¹ is <b>${k - l}</b> (the difference of the two overlap values — this is the nontrivial invariant).`;
    }
  } else {
    msgHtml = `Cocycle (t_right, t_left) = (${k}, ${l}). The class in H¹(S¹, ℤ) is represented by the <b>difference ${k - l}</b>.`;
    if(k === l){
      msgHtml += ` Both overlaps equal ⇒ trivial in H¹ (can be a coboundary; click the button).`;
    } else {
      msgHtml += ` Unequal ⇒ nontrivial in H¹.`;
    }
  }
  ro.innerHTML = msgHtml;
}

kIn.addEventListener('input', ()=>{ cobMode=false; draw(); });
lIn.addEventListener('input', ()=>{ cobMode=false; draw(); });
cobBtn.addEventListener('click', ()=>{ cobMode=!cobMode; draw(); });
draw();

const EXAMPLES = {
  'exp-torus': {
    title: 'Exp on a complex torus $X = \\mathbb{C}/\\Lambda$',
    ses: ['\\underline{\\mathbb{Z}}', '\\mathcal{O}_X', '\\mathcal{O}_X^\\times'],
    groups: [
      // [H^0(F'), H^0(F), H^0(F''), H^1(F'), H^1(F), H^1(F''), H^2(F'), H^2(F), H^2(F'')]
      ['\\mathbb{Z}', '\\mathbb{C}', '\\mathbb{C}^\\times',
       '\\mathbb{Z}^{2}', '\\mathbb{C}', '\\mathrm{Pic}(X)',
       '\\mathbb{Z}', '0', '0']
    ],
    notes: [
      'H⁰(ℤ) = ℤ (constants on connected X)',
      'H⁰(𝒪) = ℂ (global holomorphic functions on a compact complex manifold)',
      'H⁰(𝒪×) = ℂ× (global nonvanishing holomorphic functions)',
      '⟶ δ: the connecting map sends 1 ∈ H⁰(𝒪×) to 0 if the function has a log; nontrivial otherwise',
      'H¹(ℤ) = ℤ² (singular cohomology of the torus)',
      'H¹(𝒪) = ℂ (Hodge theory: H¹(𝒪) has dim = g = 1 for genus-1 curve)',
      'H¹(𝒪×) = Pic(X) — extension 0 → ℂ×/ℤ² → Pic(X) → ℤ → 0 for an elliptic curve; the connected part is the Jacobian',
      'H²(ℤ) = ℤ — the fundamental class',
      'H²(𝒪) = 0 (dimension 1, so stops)',
      'H²(𝒪×) = 0 — Brauer group vanishes here'
    ]
  },
  'exp-cx': {
    title: 'Exp on $\\mathbb{C}^\\times$',
    ses: ['\\underline{\\mathbb{Z}}', '\\mathcal{O}', '\\mathcal{O}^\\times'],
    groups: [
      ['\\mathbb{Z}', '\\mathcal{O}(\\mathbb{C}^\\times)', '\\mathcal{O}^\\times(\\mathbb{C}^\\times)',
       '\\mathbb{Z}', '0', '0',
       '0', '0', '0']
    ],
    notes: [
      'H⁰(ℤ) = ℤ',
      'H⁰(𝒪) = holomorphic functions on ℂ× — infinite-dim',
      'H⁰(𝒪×) = nonvanishing holomorphic ≅ ℤ × 𝒪×(ℂ×)/ℤ — the ℤ is winding!',
      '⟶ δ = winding number: sends z ↦ 1 ∈ H¹(ℤ)',
      'H¹(ℤ) = ℤ (ℂ× is homotopy equivalent to S¹)',
      'H¹(𝒪) = 0 (𝒪 is fine, or: Dolbeault + Stein)',
      'H¹(𝒪×) = Pic(ℂ×) = 0',
      'higher H^i all vanish — 1-real-dim rational homotopy'
    ]
  },
  'twist-pt': {
    title: '$0 \\to \\mathcal{O}(-1) \\to \\mathcal{O} \\to \\mathcal{O}_p \\to 0$ on $\\mathbb{P}^1$',
    ses: ['\\mathcal{O}(-1)', '\\mathcal{O}', '\\mathcal{O}_p'],
    groups: [
      ['0', 'k', 'k',
       '0', '0', '0',
       '0', '0', '0']
    ],
    notes: [
      'H⁰(𝒪(-1)) = 0 (no degree -1 global sections)',
      'H⁰(𝒪) = k (constants)',
      'H⁰(𝒪_p) = k (skyscraper: stalk is k)',
      '⟶ δ: constants restrict to the stalk at p → connecting map is zero (the map k → k is iso; nothing to lift)',
      'H¹(𝒪(-1)) = 0 (vanishing, degree ≥ -1)',
      'H¹(𝒪) = 0 (𝒪 on ℙ¹)',
      'H¹(𝒪_p) = 0 (skyscraper on a point is flasque)',
      'LES terminates: everything vanishes beyond H⁰'
    ]
  }
};
const pick = $('#les-pick'), prev = $('#les-prev'), next = $('#les-next'), all = $('#les-all'), reset = $('#les-reset');
const svg = $('#les-svg'), ro = $('#les-ro');
let key = pick.value, step = 0;

function draw(){
  while(svg.firstChild) svg.removeChild(svg.firstChild);
  const E = EXAMPLES[key];
  if(!E) return;
  // 9 groups in a 3x3 grid: rows are degree 0,1,2; cols are F', F, F''
  // Better: draw them in a snake: H^0(F')→H^0(F)→H^0(F'')→δ→H^1(F')→H^1(F)→H^1(F'')→δ→...
  const groups = E.groups[0];
  const maxStep = groups.length + 2; // up to 11: all 9 groups drawn plus δ highlights

  const W=860, H=300;
  const cols = 3, rows = 3;
  const xOff = 100, yOff = 60, dx = 210, dy = 80;
  const pos = (r,c) => [xOff + c*dx, yOff + r*dy];

  // draw title
  const title = SVG('text',{x:20,y:24,'font-size':13,fill:'#fff','font-weight':600});
  title.textContent = 'Long exact sequence — ' + key;
  svg.appendChild(title);
  // column headers
  const hd = SVG('text',{x:xOff,y:42,'font-size':12,fill:'var(--mute)'});
  hd.textContent = "F'";
  svg.appendChild(hd);
  const hd2 = SVG('text',{x:xOff+dx,y:42,'font-size':12,fill:'var(--mute)'});
  hd2.textContent = 'F';
  svg.appendChild(hd2);
  const hd3 = SVG('text',{x:xOff+2*dx,y:42,'font-size':12,fill:'var(--mute)'});
  hd3.textContent = "F''";
  svg.appendChild(hd3);
  // row labels
  for(let r=0;r<rows;r++){
    const t = SVG('text',{x:30,y:yOff + r*dy + 4,'font-size':13,fill:'var(--mute)'});
    t.textContent = `H${toSuperscript(r)}`;
    svg.appendChild(t);
  }

  // boxes
  for(let i=0;i<groups.length;i++){
    const r = Math.floor(i/3), c = i%3;
    const [x,y] = pos(r,c);
    const visible = step > i;
    const isH0 = r===0, isH1 = r===1, isH2 = r>=2;
    const color = isH0?'var(--green)':(isH1?'var(--yellow)':'var(--pink)');
    const fill = visible? color : 'var(--panel2)';
    const stroke = color;
    const alpha = visible?1:0.3;
    svg.appendChild(SVG('rect',{x:x-70,y:y-22,width:140,height:44,
      fill:'var(--panel2)',stroke:stroke,'stroke-width':1.5,rx:6,'fill-opacity':alpha}));
    const t = SVG('foreignObject',{x:x-68,y:y-20,width:136,height:40});
    const div = document.createElementNS('http://www.w3.org/1999/xhtml','div');
    div.setAttribute('style',`display:flex;align-items:center;justify-content:center;height:100%;color:${visible?'#fff':'#555'};font-size:14px;opacity:${alpha}`);
    div.innerHTML = `$${groups[i]}$`;
    t.appendChild(div);
    svg.appendChild(t);
  }

  // arrows
  for(let i=0;i<groups.length;i++){
    const r = Math.floor(i/3), c = i%3;
    const [x,y] = pos(r,c);
    if(c<2 && step > i){
      const [x2,y2] = pos(r,c+1);
      drawArrow(svg, [x+70,y], [x2-70,y2], {color:'var(--blue)', markerId:'les-arr-b', width:1.5});
    }
    // delta: from (r,2) to (r+1,0)
    if(c===2 && r<rows-1 && step > i+0.5){
      const [x2,y2] = pos(r+1,0);
      // curved down-and-left
      drawArrow(svg, [x, y+22], [x2, y2-22], {
        color:'var(--violet)', markerId:'les-arr-v',
        curve:80, label:'δ', labelSide:0, width:1.6
      });
    }
  }

  // notes
  const shown = Math.min(step, E.notes.length);
  let html = `<b>${E.title}</b><br>`;
  for(let j=0;j<shown;j++){
    html += `<span style="color:${E.notes[j].startsWith('⟶ δ')?'var(--violet)':'var(--ink)'}">• ${E.notes[j]}</span><br>`;
  }
  ro.innerHTML = html;
  reKatex(ro);
  // katex in the svg foreignObjects
  svg.querySelectorAll('foreignObject div').forEach(el=>reKatex(el));
}
function toSuperscript(n){ return ['⁰','¹','²','³'][n] || String(n); }

pick.addEventListener('change', ()=>{ key = pick.value; step = 0; draw(); });
prev.addEventListener('click', ()=>{ step = Math.max(0, step-1); draw(); });
next.addEventListener('click', ()=>{ step = Math.min(20, step+1); draw(); });
all.addEventListener('click', ()=>{ step = 20; draw(); });
reset.addEventListener('click', ()=>{ step = 0; draw(); });
draw();

const svg = $('#p1-svg'), ro = $('#p1-ro');
const nIn = $('#p1-n'), nVal = $('#p1-n-val');

function draw(){
  while(svg.firstChild) svg.removeChild(svg.firstChild);
  const n = +nIn.value;
  nVal.textContent = `n = ${n}`;

  // Čech: C^0 = k[x] ⊕ x^n k[x^{-1}]  →  C^1 = k[x,x^{-1}]
  // H^0 = span{x^k : 0 ≤ k ≤ n}   dim = max(n+1,0)
  // H^1 = span{x^k : n < k < 0} (when n ≤ -2)   dim = max(-n-1,0)
  const h0 = Math.max(n+1, 0);
  const h1 = Math.max(-n-1, 0);

  // Boxes for C^0 terms and C^1
  const W=820, H=260;
  const boxA = {x:60, y:60, w:210, h:70, title:'𝒪(n)(U₀)', body:'k[x]'};
  const boxB = {x:60, y:150, w:210, h:70, title:'𝒪(n)(U₁)', body:'xⁿ · k[x⁻¹]'};
  const boxC = {x:540, y:105, w:220, h:70, title:'𝒪(n)(U₀ ∩ U₁)', body:'k[x, x⁻¹]'};

  function drawBox(b, color){
    svg.appendChild(SVG('rect',{x:b.x,y:b.y,width:b.w,height:b.h,rx:8,fill:'var(--panel2)',stroke:color,'stroke-width':1.5}));
    const t = SVG('text',{x:b.x+10,y:b.y+20,'font-size':12,fill:'var(--mute)'});
    t.textContent = b.title; svg.appendChild(t);
    const t2 = SVG('text',{x:b.x+b.w/2,y:b.y+48,'font-size':16,fill:'#fff','text-anchor':'middle','font-weight':600});
    t2.textContent = b.body; svg.appendChild(t2);
  }
  drawBox(boxA, 'var(--blue)');
  drawBox(boxB, 'var(--blue)');
  drawBox(boxC, 'var(--pink)');

  // big C^0 / C^1 labels
  const labA = SVG('text',{x:20,y:50,'font-size':16,fill:'var(--yellow)','font-weight':600});
  labA.textContent = 'Č⁰';
  svg.appendChild(labA);
  const labC = SVG('text',{x:500,y:90,'font-size':16,fill:'var(--yellow)','font-weight':600});
  labC.textContent = 'Č¹';
  svg.appendChild(labC);

  // Arrows: (f, g) ↦ g − f
  drawArrow(svg, [boxA.x+boxA.w, boxA.y+boxA.h/2], [boxC.x, boxC.y+20], {
    color:'var(--ink)', markerId:'p1-arr', label:'−f', labelSide:1, curve:-14});
  drawArrow(svg, [boxB.x+boxB.w, boxB.y+boxB.h/2], [boxC.x, boxC.y+boxC.h-20], {
    color:'var(--ink)', markerId:'p1-arr', label:'+g', labelSide:0, curve:14});

  // Compute H^0 and H^1 bases
  let h0basis = [];
  for(let k=0;k<=n;k++) h0basis.push(k===0?'1':(k===1?'x':'x^'+k));
  let h1basis = [];
  for(let k=n+1;k<=-1;k++) h1basis.push(k===-1?'x⁻¹':('x^'+k));

  const short = (arr) => {
    if(!arr.length) return '0';
    return 'span{' + arr.join(', ') + '}';
  };

  // Readout
  let msg = `<b>O(${n}) on ℙ¹, via Čech on the affine cover {U₀, U₁}.</b><br>`+
            `Č⁰ = k[x] ⊕ xⁿ·k[x⁻¹]; &nbsp; Č¹ = k[x, x⁻¹]; &nbsp; d(f, g) = g − f.<br>`;
  msg += `ker d = polynomials lying in both summands = <b>${short(h0basis)}</b> &nbsp; ⟹ dim H⁰ = <b>${h0}</b><br>`;
  msg += `coker d = Laurent polys modulo (k[x] + xⁿk[x⁻¹]) = <b>${short(h1basis)}</b> &nbsp; ⟹ dim H¹ = <b>${h1}</b><br>`;
  msg += `<span style="color:var(--mute)">Check: dim H⁰ = max(n+1, 0) = ${h0}; &nbsp; dim H¹ = max(−n−1, 0) = ${h1}.</span>`;
  if(n >= 0){
    msg += `<br><span style="color:var(--green)">Since n = ${n} ≥ 0, sections are degree-${n} homogeneous polynomials in X₀, X₁: {${(function(){const a=[]; for(let i=0;i<=n;i++) a.push((n-i===0?'':'X₀'+(n-i===1?'':toSup(n-i))) + (i===0?'':'X₁' + (i===1?'':toSup(i))) || '1'); return a.join(', ');})()}}.</span>`;
  } else if(n <= -2){
    msg += `<br><span style="color:var(--pink)">Since n = ${n} ≤ −2, H¹ has dimension ${h1}; generators given by Laurent monomials x⁻¹, ..., x^${n+1}.</span>`;
  } else {
    msg += `<br><span style="color:var(--mute)">For n = ${n} (i.e., n ∈ {−1}), both H⁰ and H¹ vanish — the "trivial" case.</span>`;
  }
  ro.innerHTML = msg;
}
function toSup(k){
  return String(k).split('').map(c=>({'0':'⁰','1':'¹','2':'²','3':'³','4':'⁴','5':'⁵','6':'⁶','7':'⁷','8':'⁸','9':'⁹'}[c])).join('');
}

nIn.addEventListener('input', draw);
draw();

const nIn = $('#tab-n'), rIn = $('#tab-r'), nVal = $('#tab-n-val'), rVal = $('#tab-r-val');
const host = $('#tab-host'), ro = $('#tab-ro');

function dim(n, d, i){
  if(i < 0 || i > n) return 0;
  if(i === 0){
    return d >= 0 ? binom(n+d, n) : 0;
  }
  if(i === n){
    return d <= -n-1 ? binom(-d-1, n) : 0;
  }
  return 0;
}

function draw(){
  const n = +nIn.value, r = +rIn.value;
  nVal.textContent = `n = ${n}`;
  rVal.textContent = `d ∈ [−${r}, ${r}]`;

  host.innerHTML = '';
  const tbl = document.createElement('table');
  tbl.className = 'grid';
  // header
  const thead = document.createElement('tr');
  const th0 = document.createElement('th'); th0.textContent = 'd \\ i'; thead.appendChild(th0);
  for(let i=0;i<=n;i++){
    const th = document.createElement('th'); th.textContent = 'H'+toSup(i); thead.appendChild(th);
  }
  tbl.appendChild(thead);
  // rows
  for(let d=r; d>=-r; d--){
    const tr = document.createElement('tr');
    const th = document.createElement('th'); th.textContent = 'd = '+d; tr.appendChild(th);
    for(let i=0;i<=n;i++){
      const td = document.createElement('td');
      const v = dim(n, d, i);
      td.textContent = v;
      if(v===0){ td.className = 'zero'; }
      else if(i===0){ td.className = 'pos'; }
      else if(i===n){ td.className = 'top'; }
      // highlight duality pairs around the midpoint -n/2 - 1/2
      tr.appendChild(td);
    }
    tbl.appendChild(tr);
  }
  host.appendChild(tbl);
  let html = `ℙ<sup>${n}</sup>, d ∈ [−${r}, ${r}]. &nbsp;<b>Duality:</b> dim H⁰(𝒪(d)) = dim H<sup>${n}</sup>(𝒪(−d−${n+1})). `;
  html += `<br>E.g.: dim H⁰(𝒪(${r})) = ${dim(n,r,0)}, &nbsp; dim H<sup>${n}</sup>(𝒪(${-r-n-1})) = ${dim(n,-r-n-1,n)} — equal.`;
  ro.innerHTML = html;
}
function toSup(k){
  return String(k).split('').map(c=>({'0':'⁰','1':'¹','2':'²','3':'³','4':'⁴','5':'⁵','6':'⁶','7':'⁷','8':'⁸','9':'⁹'}[c])).join('');
}
nIn.addEventListener('input', draw);
rIn.addEventListener('input', draw);
draw();

const nIn = $('#pic-n'), dIn = $('#pic-d'), nVal = $('#pic-n-val'), dVal = $('#pic-d-val');
const svg = $('#pic-svg'), ro = $('#pic-ro');

function draw(){
  while(svg.firstChild) svg.removeChild(svg.firstChild);
  const n = +nIn.value, d = +dIn.value;
  nVal.textContent = `n = ${n}`;
  dVal.textContent = `d = ${d}`;

  const W=820, H=220;
  const axisY = 120;
  // number line from -8 to 8
  const xmin=-8, xmax=8;
  const mapX = v => 60 + (v - xmin)/(xmax - xmin) * (W - 120);

  // axis
  svg.appendChild(SVG('line',{x1:mapX(xmin), y1:axisY, x2:mapX(xmax), y2:axisY,
    stroke:'var(--line)','stroke-width':1.5}));
  // ticks
  for(let v=xmin;v<=xmax;v++){
    const x = mapX(v);
    svg.appendChild(SVG('line',{x1:x,y1:axisY-5,x2:x,y2:axisY+5,stroke:'var(--mute)','stroke-width':1}));
    const t = SVG('text',{x:x,y:axisY+20,'font-size':11,fill:'var(--mute)','text-anchor':'middle'});
    t.textContent = v; svg.appendChild(t);
  }
  // dot for d
  svg.appendChild(SVG('circle',{cx:mapX(d),cy:axisY,r:7,fill:'var(--yellow)',stroke:'#111','stroke-width':1.5}));
  const tip = SVG('text',{x:mapX(d),y:axisY - 16,'font-size':13,fill:'var(--yellow)','text-anchor':'middle','font-weight':600});
  tip.textContent = `O(${d})`;
  svg.appendChild(tip);

  // duality partner
  const dprime = -d - n - 1;
  if(dprime >= xmin && dprime <= xmax){
    svg.appendChild(SVG('circle',{cx:mapX(dprime),cy:axisY,r:5,fill:'var(--violet)',stroke:'#111','stroke-width':1.2}));
    const t2 = SVG('text',{x:mapX(dprime),y:axisY + 38,'font-size':11,fill:'var(--violet)','text-anchor':'middle'});
    t2.textContent = `dual: O(${dprime})`;
    svg.appendChild(t2);
    // dashed arc connecting
    const x1 = mapX(d), x2 = mapX(dprime);
    const midX = (x1+x2)/2, midY = axisY - 40;
    svg.appendChild(SVG('path',{
      d:`M${x1} ${axisY-10} Q ${midX} ${midY} ${x2} ${axisY-10}`,
      fill:'none',stroke:'var(--violet)','stroke-width':1,'stroke-dasharray':'4 3'
    }));
  }

  // title
  const tt = SVG('text',{x:60,y:32,'font-size':14,fill:'#fff','font-weight':600});
  tt.textContent = `Pic(ℙ${toSup(n)}) ≅ ℤ · [O(1)]`;
  svg.appendChild(tt);
  const tt2 = SVG('text',{x:60,y:52,'font-size':11,fill:'var(--mute)'});
  tt2.textContent = `every line bundle is O(d) for a unique d; tensor = addition of integers`;
  svg.appendChild(tt2);

  // label ω_Pn
  const xw = mapX(-n-1);
  if(xw >= 60 && xw <= W-60){
    svg.appendChild(SVG('circle',{cx:xw,cy:axisY,r:5,fill:'var(--green)',stroke:'#111','stroke-width':1.2}));
    const tw = SVG('text',{x:xw,y:axisY - 16,'font-size':11,fill:'var(--green)','text-anchor':'middle'});
    tw.textContent = `ω = O(${-n-1})`;
    svg.appendChild(tw);
  }

  // readout
  const h0 = d >= 0 ? binom(n+d,n) : 0;
  const hn = d <= -n-1 ? binom(-d-1, n) : 0;
  let html = `<b>O(${d}) on ℙ${toSup(n)}.</b> &nbsp;`;
  html += `degree = ${d}; &nbsp; dim H⁰ = <b>${h0}</b>; &nbsp; dim H<sup>${n}</sup> = <b>${hn}</b>; &nbsp; intermediate H<sup>i</sup> vanish.<br>`;
  html += `Serre dual partner: O(${-d-n-1}) — <span style="color:var(--violet)">dim H⁰ of partner = ${(-d-n-1>=0)?binom(n + (-d-n-1),n):0}</span>, which matches dim H<sup>${n}</sup>(O(${d})) = ${hn}.`;
  if(d === -n-1){
    html += `<br><span style="color:var(--green)">This is the canonical bundle: ω<sub>ℙ${toSup(n)}</sub> = O(−${n+1}).</span>`;
  }
  if(d === 0){
    html += `<br><span style="color:var(--mute)">Trivial line bundle.</span>`;
  }
  ro.innerHTML = html;
}
