  const W=820, H=260;
  const boxA = {x:60, y:60, w:210, h:70, title:'𝒪(n)(U₀)', body:'k[x]'};
  const boxB = {x:60, y:150, w:210, h:70, title:'𝒪(n)(U₁)', body:'xⁿ · k[x⁻¹]'};
  const boxC = {x:540, y:105, w:220, h:70, title:'𝒪(n)(U₀ ∩ U₁)', body:'k[x, x⁻¹]'};

  function drawBox(b, color){
    svg.appendChild(SVG('rect',{x:b.x,y:b.y,width:b.w,height:b.h,rx:8,fill:'var(--panel2)',stroke:color,'stroke-width':1.5}));
    const t = SVG('text',{x:b.x+10,y:b.y+20,'font-size':12,fill:'var(--mute)'});
    t.textContent = b.title; svg.appendChild(t);
    const t2 = SVG('text',{x:b.x+b.w/2,y:b.y+48,'font-size':16,fill:'#fff','text-anchor':'middle','font-weight':600});
    t2.textContent = b.body; svg.appendChild(t2);
  }
  drawBox(boxA, 'var(--blue)');
  drawBox(boxB, 'var(--blue)');
  drawBox(boxC, 'var(--pink)');

  // big C^0 / C^1 labels
  const labA = SVG('text',{x:20,y:50,'font-size':16,fill:'var(--yellow)','font-weight':600});
  labA.textContent = 'Č⁰';
  svg.appendChild(labA);
  const labC = SVG('text',{x:500,y:90,'font-size':16,fill:'var(--yellow)','font-weight':600});
  labC.textContent = 'Č¹';
  svg.appendChild(labC);

  // Arrows: (f, g) ↦ g − f
  drawArrow(svg, [boxA.x+boxA.w, boxA.y+boxA.h/2], [boxC.x, boxC.y+20], {
    color:'var(--ink)', markerId:'p1-arr', label:'−f', labelSide:1, curve:-14});
  drawArrow(svg, [boxB.x+boxB.w, boxB.y+boxB.h/2], [boxC.x, boxC.y+boxC.h-20], {
    color:'var(--ink)', markerId:'p1-arr', label:'+g', labelSide:0, curve:14});

  // Compute H^0 and H^1 bases
  let h0basis = [];
  for(let k=0;k<=n;k++) h0basis.push(k===0?'1':(k===1?'x':'x^'+k));
  let h1basis = [];
  for(let k=n+1;k<=-1;k++) h1basis.push(k===-1?'x⁻¹':('x^'+k));

  const short = (arr) => {
    if(!arr.length) return '0';
    return 'span{' + arr.join(', ') + '}';
  };

  // Readout
  let msg = `<b>O(${n}) on ℙ¹, via Čech on the affine cover {U₀, U₁}.</b><br>`+
            `Č⁰ = k[x] ⊕ xⁿ·k[x⁻¹]; &nbsp; Č¹ = k[x, x⁻¹]; &nbsp; d(f, g) = g − f.<br>`;
  msg += `ker d = polynomials lying in both summands = <b>${short(h0basis)}</b> &nbsp; ⟹ dim H⁰ = <b>${h0}</b><br>`;
  msg += `coker d = Laurent polys modulo (k[x] + xⁿk[x⁻¹]) = <b>${short(h1basis)}</b> &nbsp; ⟹ dim H¹ = <b>${h1}</b><br>`;
  msg += `<span style="color:var(--mute)">Check: dim H⁰ = max(n+1, 0) = ${h0}; &nbsp; dim H¹ = max(−n−1, 0) = ${h1}.</span>`;
  if(n >= 0){
    msg += `<br><span style="color:var(--green)">Since n = ${n} ≥ 0, sections are degree-${n} homogeneous polynomials in X₀, X₁: {${(function(){const a=[]; for(let i=0;i<=n;i++) a.push((n-i===0?'':'X₀'+(n-i===1?'':toSup(n-i))) + (i===0?'':'X₁' + (i===1?'':toSup(i))) || '1'); return a.join(', ');})()}}.</span>`;
  } else if(n <= -2){
    msg += `<br><span style="color:var(--pink)">Since n = ${n} ≤ −2, H¹ has dimension ${h1}; generators given by Laurent monomials x⁻¹, ..., x^${n+1}.</span>`;
  } else {
    msg += `<br><span style="color:var(--mute)">For n = ${n} (i.e., n ∈ {−1}), both H⁰ and H¹ vanish — the "trivial" case.</span>`;
  }
  ro.innerHTML = msg;
}
function toSup(k){
  return String(k).split('').map(c=>({'0':'⁰','1':'¹','2':'²','3':'³','4':'⁴','5':'⁵','6':'⁶','7':'⁷','8':'⁸','9':'⁹'}[c])).join('');
}

