const nSel = $('#mon-n'), dIn = $('#mon-d'), dVal = $('#mon-d-val');
const svg = $('#mon-svg'), ro = $('#mon-ro');

function enumerate(n, d){
  // enumerate all (a_0, ..., a_n) with a_i ≥ 0, sum = d
  const out = [];
  function rec(idx, rem, cur){
    if(idx === n){
      cur.push(rem);
      out.push(cur.slice());
      cur.pop();
      return;
    }
    for(let k=0;k<=rem;k++){
      cur.push(k);
      rec(idx+1, rem-k, cur);
      cur.pop();
    }
  }
  rec(0, d, []);
  return out;
}
function monoString(a){
  let s = '';
  for(let i=0;i<a.length;i++){
    if(a[i]===0) continue;
    s += 'X' + toSub(i);
    if(a[i]>1) s += toSup(a[i]);
  }
  return s || '1';
}
function toSup(k){
  return String(k).split('').map(c=>({'0':'⁰','1':'¹','2':'²','3':'³','4':'⁴','5':'⁵','6':'⁶','7':'⁷','8':'⁸','9':'⁹'}[c])).join('');
}
function toSub(k){
  return String(k).split('').map(c=>({'0':'₀','1':'₁','2':'₂','3':'₃','4':'₄','5':'₅','6':'₆','7':'₇','8':'₈','9':'₉'}[c])).join('');
}

function draw(){
  while(svg.firstChild) svg.removeChild(svg.firstChild);
  const n = +nSel.value, d = +dIn.value;
  dVal.textContent = `d = ${d}`;

  const W=820, H=320;
  // title
  const tt = SVG('text',{x:20,y:28,'font-size':15,fill:'#fff','font-weight':600});
  tt.textContent = `Global sections of O(${d}) on ℙ${toSup(n)}`;
  svg.appendChild(tt);

  const mons = enumerate(n, d);
  const count = mons.length;

  const tt2 = SVG('text',{x:20,y:48,'font-size':12,fill:'var(--mute)'});
  tt2.textContent = `binomial (n+d choose n) = binomial (${n}+${d} choose ${n}) = ${count}`;
  svg.appendChild(tt2);

  if(n === 1){
    // list monomials X_0^(d-i) X_1^i along a horizontal band
    const y = 150;
    const nM = mons.length;
    for(let i=0;i<nM;i++){
      const x = 60 + i*(W-120)/Math.max(1,nM-1);
      const m = mons[i];
      svg.appendChild(SVG('circle',{cx:x,cy:y,r:14,fill:'var(--panel2)',stroke:'var(--blue)','stroke-width':1.5}));
      const t = SVG('text',{x,y:y+4,'font-size':11,fill:'#fff','text-anchor':'middle'});
      t.textContent = monoString(m);
      svg.appendChild(t);
      // below: dehomogenized on U_0: x^i
      const t2 = SVG('text',{x,y:y+45,'font-size':11,fill:'var(--mute)','text-anchor':'middle'});
      t2.textContent = (m[1]===0? '1' : (m[1]===1? 'x' : 'x'+toSup(m[1])));
      svg.appendChild(t2);
    }
    const labU0 = SVG('text',{x:20,y:y+49,'font-size':11,fill:'var(--mute)'});
    labU0.textContent = 'on U₀ (coord x):';
    svg.appendChild(labU0);
  } else if(n === 2){
    // Draw as triangular lattice: (a_0, a_1, a_2) with a_0+a_1+a_2 = d
    // Use (a_1, a_2) in a triangle: a_1 in [0, d], a_2 in [0, d-a_1]
    const cx=W/2, cy=180, sc=Math.min(40, (W-200)/(d+1));
    // axes
    function pos(a1, a2){
      // 2D isometric
      return [cx + (a1 - a2)*sc, cy + (d - a1 - a2)*(-sc*0.8) + 60];
    }
    for(const m of mons){
      const [a0,a1,a2] = m;
      const [x,y] = pos(a1,a2);
      svg.appendChild(SVG('circle',{cx:x,cy:y,r:15,fill:'var(--panel2)',stroke:'var(--blue)','stroke-width':1.3}));
      const t = SVG('text',{x,y:y+4,'font-size':10,fill:'#fff','text-anchor':'middle'});
      t.textContent = `${a0},${a1},${a2}`;
      svg.appendChild(t);
    }
    // legend
    const lg = SVG('text',{x:20,y:H-16,'font-size':11,fill:'var(--mute)'});
    lg.textContent = 'lattice points (a₀, a₁, a₂) with a₀+a₁+a₂ = d, aᵢ ≥ 0';
    svg.appendChild(lg);
  } else {
    // n = 3: just list
    const colW = 120, rowH = 24;
    const cols = Math.floor((W-40)/colW);
    for(let i=0;i<mons.length;i++){
      const col = i % cols, row = Math.floor(i / cols);
      const x = 40 + col*colW, y = 90 + row*rowH;
      const t = SVG('text',{x,y,'font-size':11,fill:'var(--ink)'});
      t.textContent = monoString(mons[i]);
      svg.appendChild(t);
    }
  }

  // Čech cocycle view for P^1
  let msg = `<b>ℙ${toSup(n)}, O(${d}).</b> &nbsp;Number of monomials = C(n+d, n) = C(${n+d}, ${n}) = <b>${count}</b>.`;
  if(n === 1){
    msg += `<br><span style="color:var(--blue)">On the affine chart U₀ (coord x), these become: 1, x, x², …, x<sup>${d}</sup>. On U₁ (coord y = 1/x): y<sup>${d}</sup>, …, y, 1 (equivalently x<sup>0</sup>, x, …, x<sup>${d}</sup> after twisting by x<sup>${d}</sup>).</span>`;
  }
  if(n === 2){
    msg += `<br><span style="color:var(--blue)">Arranged on the simplex {(a₀,a₁,a₂) : a₀+a₁+a₂ = ${d}}. Corners of the simplex: X₀<sup>${d}</sup>, X₁<sup>${d}</sup>, X₂<sup>${d}</sup>.</span>`;
  }
  if(d === 0){
    msg += `<br><span style="color:var(--mute)">d = 0: only the constant section.</span>`;
  }
  ro.innerHTML = msg;
}

nSel.addEventListener('change', draw);
dIn.addEventListener('input', draw);
draw();
